## Okuqinzo

class MyClass(object):
    def __init__(self):
        self.x = 123

    @property
    def x(self):
        return self._x

    @x.setter
    def x(self, value):
        self._x = value

    def mymethod(self):
        return self.x

    def myothermethod(self):
        return self.x + 1

    def myotherothermethod(self):
        return self.x + 2
